// Build the ICS content for VEVENT (Calendar Event)
const body = $('Webhook - Create Event').first().json.body;
const eventId = Date.now();

// Format date to iCal format (YYYYMMDDTHHMMSSZ)
const formatICalDate = (d) => {
  const year = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  const hours = String(d.getUTCHours()).padStart(2, '0');
  const minutes = String(d.getUTCMinutes()).padStart(2, '0');
  const seconds = String(d.getUTCSeconds()).padStart(2, '0');
  return `${year}${month}${day}T${hours}${minutes}${seconds}Z`;
};

// Format date to iCal date only (YYYYMMDD) for all-day events
const formatICalDateOnly = (d) => {
  const year = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${year}${month}${day}`;
};

// Parse date string to Date object
const parseDate = (dateStr) => {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  return isNaN(d.getTime()) ? null : d;
};

// Get calendar name (default to 'default')
const calendarName = body.calendar || 'default';
const now = new Date();
const dtstamp = formatICalDate(now);

// Start and End dates
const startDate = parseDate(body.start);
const endDate = parseDate(body.end);
const isAllDay = body.allDay === true;

// Build VEVENT content
const lines = [];
lines.push('BEGIN:VCALENDAR');
lines.push('VERSION:2.0');
lines.push('PRODID:-//n8n//Nextcloud//EN');
lines.push('CALSCALE:GREGORIAN');
lines.push('BEGIN:VEVENT');
lines.push(`UID:n8n-event-${eventId}`);
lines.push(`DTSTAMP:${dtstamp}`);

// SUMMARY (required)
if (body.title) {
  lines.push(`SUMMARY:${body.title}`);
}

// Start Date/Time
if (startDate) {
  if (isAllDay) {
    lines.push(`DTSTART;VALUE=DATE:${formatICalDateOnly(startDate)}`);
  } else {
    lines.push(`DTSTART:${formatICalDate(startDate)}`);
  }
}

// End Date/Time
if (endDate) {
  if (isAllDay) {
    lines.push(`DTEND;VALUE=DATE:${formatICalDateOnly(endDate)}`);
  } else {
    lines.push(`DTEND:${formatICalDate(endDate)}`);
  }
} else if (startDate && !isAllDay) {
  // Default to 1 hour event if no end date
  const defaultEnd = new Date(startDate.getTime() + 60 * 60 * 1000);
  lines.push(`DTEND:${formatICalDate(defaultEnd)}`);
}

// DESCRIPTION
if (body.description) {
  lines.push(`DESCRIPTION:${body.description}`);
}

// LOCATION
if (body.location) {
  lines.push(`LOCATION:${body.location}`);
}

// STATUS: TENTATIVE, CONFIRMED, CANCELLED
if (body.status) {
  const statusMap = {
    'tentative': 'TENTATIVE',
    'confirmed': 'CONFIRMED',
    'cancelled': 'CANCELLED',
    'TENTATIVE': 'TENTATIVE',
    'CONFIRMED': 'CONFIRMED',
    'CANCELLED': 'CANCELLED'
  };
  lines.push(`STATUS:${statusMap[body.status] || 'CONFIRMED'}`);
} else {
  lines.push('STATUS:CONFIRMED');
}

// TRANSPARENCY (OPAQUE = blocks time, TRANSPARENT = free)
if (body.transparency) {
  const transMap = {
    'busy': 'OPAQUE',
    'free': 'TRANSPARENT',
    'OPAQUE': 'OPAQUE',
    'TRANSPARENT': 'TRANSPARENT'
  };
  lines.push(`TRANSP:${transMap[body.transparency] || 'OPAQUE'}`);
} else {
  lines.push('TRANSP:OPAQUE');
}

// PRIORITY (1=highest, 9=lowest)
if (body.priority !== undefined && body.priority !== null) {
  const priority = Math.min(9, Math.max(1, parseInt(body.priority)));
  lines.push(`PRIORITY:${priority}`);
}

// CATEGORIES
if (body.categories) {
  const cats = Array.isArray(body.categories) ? body.categories.join(',') : body.categories;
  lines.push(`CATEGORIES:${cats}`);
}

// URL
if (body.url) {
  lines.push(`URL:${body.url}`);
}

// RRULE (Recurrence Rule)
if (body.recurrence) {
  lines.push(`RRULE:${body.recurrence}`);
}

// EXDATE (Exception Dates - dates to exclude from recurrence)
if (body.exceptions) {
  const exdates = Array.isArray(body.exceptions) ? body.exceptions : [body.exceptions];
  exdates.forEach(date => {
    const d = parseDate(date);
    if (d) lines.push(`EXDATE:${formatICalDate(d)}`);
  });
}

// ATTENDEES
if (body.attendees) {
  const attendees = Array.isArray(body.attendees) ? body.attendees : [body.attendees];
  attendees.forEach(attendee => {
    if (attendee.email) {
      const cn = attendee.name ? `CN=${attendee.name};` : '';
      const partstat = attendee.status || 'NEEDS-ACTION';
      lines.push(`ATTENDEE;${cn}CUTYPE=INDIVIDUAL;ROLE=REQ-PARTICIPANT;PARTSTAT=${partstat}:mailto:${attendee.email}`);
    }
  });
}

// ORGANIZER
if (body.organizer) {
  if (body.organizer.email) {
    const cn = body.organizer.name ? `CN=${body.organizer.name};` : '';
    lines.push(`ORGANIZER;${cn}mailto:${body.organizer.email}`);
  }
}

// ALARMS (Reminders)
if (body.reminders) {
  const reminders = Array.isArray(body.reminders) ? body.reminders : [body.reminders];
  reminders.forEach(reminder => {
    const minutes = reminder.minutes || 15;
    const action = reminder.action || 'DISPLAY';
    const description = reminder.description || body.title || 'Reminder';
    lines.push('BEGIN:VALARM');
    lines.push('ACTION:' + action);
    lines.push('DESCRIPTION:' + description);
    lines.push(`TRIGGER:-PT${minutes}M`);
    lines.push('END:VALARM');
  });
} else {
  // Default reminder: 15 minutes before
  lines.push('BEGIN:VALARM');
  lines.push('ACTION:DISPLAY');
  lines.push('DESCRIPTION:Reminder');
  lines.push('TRIGGER:-PT15M');
  lines.push('END:VALARM');
}

// SEQUENCE (for tracking event versions)
if (body.sequence !== undefined) {
  lines.push(`SEQUENCE:${body.sequence}`);
} else {
  lines.push('SEQUENCE:0');
}

lines.push('END:VEVENT');
lines.push('END:VCALENDAR');

// Join with CRLF (required by iCal spec)
const icsBody = lines.join('\r\n');

return [{
  json: {
    nextcloudUrl: $('Set Config').first().json.nextcloudUrl,
    nextcloudUser: $('Set Config').first().json.nextcloudUser,
    calendarName,
    icsBody
  }
}];

const response = $input.first();
const body = $('Webhook - Create Event').first().json.body;

if (response.json.statusCode === 201 || response.json.statusCode === 204 || !response.json.error) {
  return [{
    json: {
      success: true,
      message: 'Calendar event created successfully!',
      event: {
        title: body.title,
        start: body.start || null,
        end: body.end || null,
        allDay: body.allDay || false,
        location: body.location || null,
        description: body.description || null,
        status: body.status || 'confirmed',
        calendar: body.calendar || 'default',
        recurrence: body.recurrence || null,
        attendees: body.attendees || [],
        reminders: body.reminders || [{ minutes: 15 }]
      }
    }
  }];
} else {
  return [{
    json: {
      success: false,
      message: 'Failed to create calendar event',
      error: response.json
    }
  }];
}
